import time, statistics, random
from dataclasses import dataclass, field
from typing import Callable

@dataclass
class VendorState:
    name: str
    call_fn: Callable[[str], str]
    errors: list[float] = field(default_factory=list)  # timestamps
    latencies: list[float] = field(default_factory=list)
    circuit_open: bool = False
    open_since: float = 0.0
    cooldown: float = 60.0  # seconds

    def record(self, latency: float, error: bool):
        now = time.time()
        self.latencies = [l for l in self.latencies if l < now]  # prune old
        self.errors = [e for e in self.errors if e > now - 60]
        if error:
            self.errors.append(now)
        self.latencies.append(latency)
        # Check thresholds
        err_rate = len(self.errors) / max(len(self.latencies), 1)
        p95 = sorted(self.latencies)[int(len(self.latencies) * 0.95)] if self.latencies else 0
        if err_rate > 0.05 or p95 > 5.0:
            if not self.circuit_open:
                self.circuit_open = True
                self.open_since = now
                print(f"Circuit OPEN for {self.name}: err={err_rate:.1%} p95={p95:.2f}s")
        elif self.circuit_open and now - self.open_since > self.cooldown:
            self.circuit_open = False
            print(f"Circuit CLOSED for {self.name}")

class FailoverRouter:
    def __init__(self, vendors: list[VendorState]):
        self.vendors = vendors  # ordered by priority

    def complete(self, prompt: str) -> str:
        for vendor in self.vendors:
            if vendor.circuit_open:
                continue
            t0 = time.time()
            try:
                result = vendor.call_fn(prompt)
                vendor.record(time.time() - t0, error=False)
                return result
            except Exception as e:
                vendor.record(time.time() - t0, error=True)
                print(f"Failover from {vendor.name}: {e}")
        raise RuntimeError("All vendor circuits open")
